import{_ as e,o as r,c as i,ak as t,av as o}from"./chunks/framework.DTkRX0Ot.js";const b=JSON.parse('{"title":"Port","description":"","frontmatter":{},"headers":[],"relativePath":"AUTOSAR 实战/MCAL 模块详解/Port.md","filePath":"AUTOSAR 实战/MCAL 模块详解/Port.md"}'),n={name:"AUTOSAR 实战/MCAL 模块详解/Port.md"};function p(l,a,P,d,h,c){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="port" tabindex="-1">Port <a class="header-anchor" href="#port" aria-label="Permalink to “Port”">​</a></h1><p><strong>该模块的具体使用说明可能需要结合 S32K1xx Reference Manual。</strong></p><p>该模块提供了对于整体端口（Port）的初始化功能。许多端口及其引脚的映射、定义等工作在这里完成，包括但不限于：</p><ul><li>GPIO</li><li>ADC</li><li>SPI</li><li>PWM</li><li>CAN</li><li>Etc.</li></ul><blockquote><p>查看芯片端口资源的方法：</p><p>打开 Reference Manual，找到附件：<code>S32K1xx_IO_Signal_Description_Input_Multiplexing.xlsx</code>，选择 Sheet：<code>IO Signal Table</code> 即可查看。</p></blockquote><p>定义引脚的功能有三种方式，B、C 两种在此不再赘述，用 UM 中的描述代之：</p><p><img src="'+o+'" alt=""></p><p>需要注意的是，为了调试， JTAG 相关的引脚需要被设定为 UnTouchedPortPin。EB tresos Studio 29 在 新建项目时提供了相关的模板，可以预先完成此项设置。</p><p>下面对必要的设置项逐一说明。</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to “General”">​</a></h2><h3 id="notusedportpin" tabindex="-1">NotUsedPortPin <a class="header-anchor" href="#notusedportpin" aria-label="Permalink to “NotUsedPortPin”">​</a></h3><p>该部分对没有使用（设置）的引脚进行定义，即当某个引脚没有进行特定设置/映射时的表现。</p><h4 id="portpin-mode" tabindex="-1">PortPin Mode <a class="header-anchor" href="#portpin-mode" aria-label="Permalink to “PortPin Mode”">​</a></h4><p>引脚模式，包括 GPIO（通用输入输出）、Disabled（禁用）两种模式。</p><h4 id="portpin-direction" tabindex="-1">PortPin Direction <a class="header-anchor" href="#portpin-direction" aria-label="Permalink to “PortPin Direction”">​</a></h4><p>设置引脚方向，该设置仅对 GPIO 模式有效。可以选择 OUT、IN、HIGH_Z（部分芯片不支持）模式。</p><h4 id="portpin-dse" tabindex="-1">PortPin DSE <a class="header-anchor" href="#portpin-dse" aria-label="Permalink to “PortPin DSE”">​</a></h4><p>选择该引脚的电平驱动强度为高/低。类似于AF/OD。</p><h4 id="portpin-pe" tabindex="-1">PortPin PE <a class="header-anchor" href="#portpin-pe" aria-label="Permalink to “PortPin PE”">​</a></h4><p>选择该引脚是否采用上/下拉模式。</p><h4 id="portpin-ps" tabindex="-1">PortPin PS <a class="header-anchor" href="#portpin-ps" aria-label="Permalink to “PortPin PS”">​</a></h4><p>如果 PortPin PE 选项设为 PullEnabled，该项用于选择是上拉还是下拉。</p><h3 id="portgeneral" tabindex="-1">PortGeneral <a class="header-anchor" href="#portgeneral" aria-label="Permalink to “PortGeneral”">​</a></h3><h4 id="port-setpindirection-api" tabindex="-1">Port SetPinDirection Api <a class="header-anchor" href="#port-setpindirection-api" aria-label="Permalink to “Port SetPinDirection Api”">​</a></h4><p>是否开放设置引脚方向的 API：<code>Port_SetPinDirection()</code></p><h4 id="port-setpinmode-api" tabindex="-1">Port SetPinMode Api <a class="header-anchor" href="#port-setpinmode-api" aria-label="Permalink to “Port SetPinMode Api”">​</a></h4><p>因为某些安全设定，该选项不会被实现（not supported by the safety implementation）。</p><h2 id="portcontainer" tabindex="-1">PortContainer <a class="header-anchor" href="#portcontainer" aria-label="Permalink to “PortContainer”">​</a></h2><p>该部分包含了所有端口引脚的设置。可以新建一个或多个容器用于存放这些引脚的设置。</p><h3 id="general-portnumerofportpins" tabindex="-1">General / PortNumerOfPortPins <a class="header-anchor" href="#general-portnumerofportpins" aria-label="Permalink to “General / PortNumerOfPortPins”">​</a></h3><p>制定在该 Container 容器中设置的端口数量。</p><h3 id="portpin" tabindex="-1">PortPin <a class="header-anchor" href="#portpin" aria-label="Permalink to “PortPin”">​</a></h3><p>该处用于单个引脚的设置。</p><p>如果想启用某个引脚的功能，可以在 PortPin 栏目中添加。</p><p>对于每个引脚的设置：</p><h4 id="portpin-id" tabindex="-1">PortPin Id <a class="header-anchor" href="#portpin-id" aria-label="Permalink to “PortPin Id”">​</a></h4><p>这个值是由软件指定的。生成代码时，由用户设定的 Name 字段将会被宏定义为该值。</p><h4 id="portpin-pcr" tabindex="-1">PortPin Pcr <a class="header-anchor" href="#portpin-pcr" aria-label="Permalink to “PortPin Pcr”">​</a></h4><p>Pcr 即 Port Configuration Register。该值可以由以下公式计算：</p><blockquote><p>规定 A-E 映射为 0-4，将该值设为 x；则PTx_y 的 Pcr 值为：32*x+y。</p></blockquote><p>如 PTC7 的 Pcr 值为：32*2+7=71。</p><p>具体的 PTx_y 值请参考 IO Signal Table。</p><h4 id="portpin-initial-mode" tabindex="-1">PortPin Initial Mode <a class="header-anchor" href="#portpin-initial-mode" aria-label="Permalink to “PortPin Initial Mode”">​</a></h4><p>该参数不可用，但是按照 AUTOSAR_EcucParamDef.arxml 文件的要求保留。</p><h4 id="other-conf" tabindex="-1">Other Conf <a class="header-anchor" href="#other-conf" aria-label="Permalink to “Other Conf”">​</a></h4><p>其余内容与 NotUsedPortPin 中所诠释的相同。</p>',46)])])}const m=e(n,[["render",p]]);export{b as __pageData,m as default};
